def format_findings(findings):
    formatted = []

    for f in findings:
        check_id = f.get("check_id")
        message = f.get("extra", {}).get("message", "")
        line = f.get("start", {}).get("line", "?")
        snippet = f.get("extra", {}).get("lines", "").strip()

        formatted.append(
            f"""Rule: {check_id}
            Line: {line}
            Message: {message}
            Code:
            {snippet}
            """
        )

    return "\n---\n".join(formatted)

