def get_validator(repo_path: str):
    repo = Path(repo_path)

    extensions = {p.suffix for p in repo.rglob("*") if p.is_file()}

    for ext, validator_cls in EXTENSION_MAP.items():
        if ext in extensions:
            return validator_cls(repo_path)

    return GenericValidator(repo_path)

def _mock_response(self, system: str, prompt: str) -> str:
        """
        Azure-backed implementation that returns raw model output.
        """
        response = self.client.chat.completions.create(
            model=self.model,
            messages=[
                {"role": "system", "content": system},
                {"role": "user", "content": prompt},
            ],
        )

        content = response.choices[0].message.content

        # Handle Azure returning list-style content
        if isinstance(content, list):
            return "".join(
                part.get("text", "") if isinstance(part, dict) else str(part)
                for part in content
            )

        return str(content)

