def reset_temp_repo(repo_path):
    run_git(["reset", "--hard"], repo_path)
    run_git(["clean", "-fd"], repo_path)

def _build_map(self, findings):

        vuln_map = {}

        for file in findings:
            path = file["path"]

            for vuln in file["vulnerabilities"]:

                func, param_types = self._parse_signature(vuln["function"])

                key = (
                    path,
                    vuln["function_class"],
                    func,
                    param_types
                )

                vuln_map.setdefault(key, []).append(vuln)

        return vuln_map

def _parse_signature(self, sig):
        if not sig or "(" not in sig:
            return sig, ()

        name = sig.split("(")[0]

        params = sig.split("(")[1].rstrip(")")

        if not params.strip():
            return name, ()

        types = []

        for p in params.split(","):
            p = p.strip()

            # remove variable name
            t = p.split(" ")[0]

            types.append(t)

        return name, tuple(types)

def clone_to_temp(git_url: str) -> str:
